// ─── Helpers ──────────────────────────────────────────────────────────

fn styled_field_line(label: &str, value: &str, focused: bool, error: Option<&str>) -> Line<'static> {
    let input_style = if focused {
        Style::default().fg(Color::Black).bg(Color::Cyan)
    } else {
        Style::default().fg(Color::White)
    };
    let mut spans: Vec<Span<'static>> = vec![
        Span::raw(format!("{label}: ")),
        Span::styled(format!("[{value}]"), input_style),
    ];
    if let Some(err) = error {
        spans.push(Span::styled(
            format!(" ← {err}"),
            Style::default().fg(Color::Red),
        ));
    }
    Line::from(spans)
}

pub fn key_to_input_request(key: KeyEvent) -> Option<tui_input::InputRequest> {
    use tui_input::InputRequest::*;
    match key.code {
        KeyCode::Char(c) => Some(InsertChar(c)),
        KeyCode::Backspace => Some(DeletePrevChar),
        KeyCode::Delete => Some(DeleteNextChar),
        KeyCode::Left => {
            if key.modifiers.contains(KeyModifiers::CONTROL) {
                Some(GoToPrevWord)
            } else {
                Some(GoToPrevChar)
            }
        }
        KeyCode::Right => {
            if key.modifiers.contains(KeyModifiers::CONTROL) {
                Some(GoToNextWord)
            } else {
                Some(GoToNextChar)
            }
        }
        KeyCode::Home => Some(GoToStart),
        KeyCode::End => Some(GoToEnd),
        _ => None,
    }
}

